import subprocess
import os

def convertDocument(input_file, output_file, format):
    # Construct the command for LibreOffice in headless mode
    command = [
        'libreoffice', 
        '--headless', 
        '--convert-to', 
        format, 
        '--outdir', 
        os.path.dirname(output_file), 
        input_file
    ]
    
    # Execute the command
    subprocess.run(command, check=True)
    
    # Rename output file to the desired output filename
    if os.path.isfile(os.path.join(os.path.dirname(output_file), os.path.basename(input_file).replace('.' + input_file.split('.')[-1], '.' + format))):
        os.rename(
            os.path.join(os.path.dirname(output_file), os.path.basename(input_file).replace('.' + input_file.split('.')[-1], '.' + format)), 
            output_file
        )